// ---- StateFlow and LiveData ----
// Dependencies:
// implementation("androidx.lifecycle:lifecycle-runtime-ktx:2.8.0")

// ---- StateFlow ViewModel ----
class StateFlowViewModel : ViewModel() {
    // ---- StateFlow (modern, Kotlin-first) ----
    private val _counter = MutableStateFlow(0)
    val counter: StateFlow<Int> = _counter.asStateFlow()

    private val _message = MutableStateFlow("Hello")
    val message: StateFlow<String> = _message.asStateFlow()

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading.asStateFlow()

    fun increment() {
        _counter.update { it + 1 }
    }

    fun decrement() {
        _counter.update { it - 1 }
    }

    fun setMessage(newMessage: String) {
        _message.value = newMessage
    }

    fun startLoading() {
        _isLoading.value = true
        viewModelScope.launch {
            delay(2000)
            _isLoading.value = false
        }
    }

    // ---- Combine multiple StateFlows ----
    val combined: StateFlow<String> = combine(
        counter,
        message
    ) { count, msg ->
        "Count: $count, Message: $msg"
    }.stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(),
        initialValue = "Count: 0, Message: Hello"
    )
}

// ---- LiveData ViewModel (legacy) ----
class LiveDataViewModel : ViewModel() {
    private val _counter = MutableLiveData(0)
    val counter: LiveData<Int> = _counter

    fun increment() {
        _counter.value = (_counter.value ?: 0) + 1
    }
}

// ---- StateFlow in Composable ----
@Composable
fun StateFlowScreen() {
    val viewModel: StateFlowViewModel = viewModel()
    val counter by viewModel.counter.collectAsState()
    val message by viewModel.message.collectAsState()
    val isLoading by viewModel.isLoading.collectAsState()
    val combined by viewModel.combined.collectAsState()

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // ---- Display state ----
        Text(
            text = "Counter: $counter",
            style = MaterialTheme.typography.headlineMedium
        )

        Text(
            text = message,
            style = MaterialTheme.typography.bodyLarge
        )

        Text(
            text = combined,
            style = MaterialTheme.typography.bodyMedium
        )

        // ---- Loading indicator ----
        if (isLoading) {
            CircularProgressIndicator()
        }

        // ---- Controls ----
        Row(
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = { viewModel.decrement() }) {
                Text("-")
            }
            Button(onClick = { viewModel.increment() }) {
                Text("+")
            }
        }

        OutlinedTextField(
            value = message,
            onValueChange = { viewModel.setMessage(it) },
            label = { Text("Message") },
            modifier = Modifier.fillMaxWidth()
        )

        Button(
            onClick = { viewModel.startLoading() },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Start Loading")
        }
    }
}

// ---- LiveData in Compose ----
@Composable
fun LiveDataScreen() {
    val viewModel: LiveDataViewModel = viewModel()
    val counter by viewModel.counter.observeAsState(0)

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Text(
            text = "Counter: $counter",
            style = MaterialTheme.typography.headlineLarge
        )

        Button(onClick = { viewModel.increment() }) {
            Text("Increment")
        }
    }
}

